function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    if (n === 0) {
        return -1;
    }
    const graph: [number, number][][] = Array.from({ length: n }, () => []);
    const indegree = new Array(n).fill(0);

    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const c = edge[2];
        if (v === 0) continue;
        if (u === n - 1) continue;
        graph[u].push([v, c]);
        indegree[v]++;
    }

    const queue: number[] = [];
    const order: number[] = [];

    for (let i = 0; i < n; i++) {
        if (indegree[i] === 0) {
            queue.push(i);
        }
    }

    while (queue.length > 0) {
        const u = queue.shift()!;
        order.push(u);
        for (const [v, _] of graph[u]) {
            indegree[v]--;
            if (indegree[v] === 0) {
                queue.push(v);
            }
        }
    }

    let maxCost = 0;
    for (const edge of edges) {
        if (edge[2] > maxCost) {
            maxCost = edge[2];
        }
    }

    let low = 0;
    let high = maxCost;
    let candidate = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (check(mid, order, graph, online, k, n)) {
            candidate = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return candidate;
}

function check(X: number, order: number[], graph: [number, number][][], online: boolean[], k: number, n: number): boolean {
    const dp = new Array(n).fill(Number.MAX_SAFE_INTEGER);
    dp[0] = 0;

    for (const u of order) {
        if (dp[u] === Number.MAX_SAFE_INTEGER) {
            continue;
        }
        if (dp[u] > k) {
            continue;
        }
        if (u !== 0 && u !== n - 1 && !online[u]) {
            continue;
        }

        for (const [v, c] of graph[u]) {
            if (c < X) {
                continue;
            }
            if (v !== 0 && v !== n - 1 && !online[v]) {
                continue;
            }
            const newCost = dp[u] + c;
            if (newCost < dp[v]) {
                dp[v] = newCost;
            }
        }
    }

    return dp[n - 1] <= k;
}
```

